class Resume {
  name string
  email string
  skills string[]
  years_experience int
}

function ExtractResume(raw_text: string) -> Resume {
  client "openai/gpt-4o"
  prompt #"
    Extract the candidate details from the text below.

    {{ ctx.output_format }}

    Resume text:
    {{ raw_text }}
  "#
}
